module top(input clk, input rst, input [7:0] data);
reg [7:0] r1, r2;
wire [7:0] inv = 'x;
always @(posedge clk or posedge rst) begin
  if (rst) r1 <= inv;
  else r1 <= data;
end
always @(posedge clk or posedge rst) begin
  if (rst) r2 <= inv;
  else r2 <= data;
end
endmodule

reg [7:0] reg0, reg1;
always @(posedge c or posedge r) begin
  if (r) reg0 <= 8'bx;
  else reg0 <= i0;
  if (r) reg1 <= 8'bx;
  else reg1 <= i1;
end
